CREATE TABLE IF NOT EXISTS castle_edits (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  parent_logo_id INTEGER NOT NULL REFERENCES castle_votes(logo_id),
  session_id TEXT NOT NULL,
  prompt TEXT NOT NULL,
  image_data_url TEXT NOT NULL,
  up_votes INTEGER DEFAULT 0,
  down_votes INTEGER DEFAULT 0,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

ALTER TABLE castle_edits ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Public read castle_edits" ON castle_edits FOR SELECT USING (true);
CREATE POLICY "Public insert castle_edits" ON castle_edits FOR INSERT WITH CHECK (true);
CREATE POLICY "Public update castle_edits" ON castle_edits FOR UPDATE USING (true);

-- Per-session vote tracking for edits
CREATE TABLE IF NOT EXISTS castle_edit_user_votes (
  id UUID PRIMARY KEY DEFAULT gen_random_uuid(),
  edit_id UUID NOT NULL REFERENCES castle_edits(id) ON DELETE CASCADE,
  session_id TEXT NOT NULL,
  direction TEXT NOT NULL CHECK (direction IN ('up', 'down')),
  UNIQUE(edit_id, session_id)
);

ALTER TABLE castle_edit_user_votes ENABLE ROW LEVEL SECURITY;

CREATE POLICY "Public read edit_user_votes" ON castle_edit_user_votes FOR SELECT USING (true);
CREATE POLICY "Public insert edit_user_votes" ON castle_edit_user_votes FOR INSERT WITH CHECK (true);
CREATE POLICY "Public update edit_user_votes" ON castle_edit_user_votes FOR UPDATE USING (true);
CREATE POLICY "Public delete edit_user_votes" ON castle_edit_user_votes FOR DELETE USING (true);

-- RPC for atomic edit vote adjustment
CREATE OR REPLACE FUNCTION adjust_edit_votes(p_edit_id UUID, p_up_delta INTEGER, p_down_delta INTEGER)
RETURNS void LANGUAGE plpgsql SECURITY DEFINER AS $$
BEGIN
  UPDATE castle_edits
  SET
    up_votes   = GREATEST(0, up_votes   + p_up_delta),
    down_votes = GREATEST(0, down_votes + p_down_delta)
  WHERE id = p_edit_id;
END;
$$;

GRANT EXECUTE ON FUNCTION adjust_edit_votes(UUID, INTEGER, INTEGER) TO anon, authenticated;
